(98, '2017-07-05', '1.9.7', '<li>Perbaikan Halaman Dashboard</li>\r\n<ol type=\"a\">\r\n<li>Perbaikan/Revisi <i>CSS programming language</i> untuk warna latar dan tulisan pada tabel \"Receive and Consumpt\"</li>\r\n<li>Perbaikan error pada unit pembangkit PLTG MPP\r\n</ol>\r\n\r\n<li>Perbaikan/Revisi SOP pengiriman dan penerimaan BBM pada aplikasi SIMBA</li>\r\n<li>Penambahan \"SIMBA Photo Gallery\"</li>\r\n<li>Perbaikan/Revisi \"Footer Text Slider\"</li>\r\n<li>Perbaikan bug dan error</li>'),
(99, '2017-08-29', '1.9.8', '<li>Penambahan <b>GRIPPY SEARCH</b></li>\r\n<ol type=\"a\">\r\n<li>Keyboardless search engine on SIMBA</li>\r\n<li>Fitur pencarian \"Big Data\"</li>\r\n<li>Mengumpulkan data berdasarkan sortir button dan melakukan export ke Excel, Graph Visualization (KPI) serta Printer</li>\r\n</ol>\r\n\r\n<li>Penambahan tagging seluruh single line bahan bakar unit pembangkit</li>\r\n<li>Perbaikan data monitoring operasi unit PLTG MPP dan PLTD Bugak Berawang</li>\r\n<li>Perbaikan bug dan error</li>\r\n<li>Minor Code Improvement</li>');
